import json
import pymysql
import os
from typing import Dict, Any, List

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    # Validate input
    if not isinstance(event, dict):
        return {
            'statusCode': 400,
            'body': json.dumps({'error': 'Invalid request format'})
        }
    
    # Extract query parameters
    query_params = event.get('queryStringParameters', {})
    if not query_params:
        query_params = {}
    
    # Define allowed search fields
    allowed_fields = {'name', 'category', 'price_min', 'price_max', 'limit'}
    
    # Validate and sanitize input parameters
    validated_params = {}
    for key, value in query_params.items():
        if key in allowed_fields:
            if key in ['price_min', 'price_max']:
                try:
                    validated_params[key] = float(value)
                except (ValueError, TypeError):
                    return {
                        'statusCode': 400,
                        'body': json.dumps({'error': f'Invalid {key} value'})
                    }
            elif key == 'limit':
                try:
                    validated_params[key] = int(value)
                    if validated_params[key] <= 0 or validated_params[key] > 1000:
                        validated_params[key] = 1000
                except (ValueError, TypeError):
                    validated_params[key] = 100
            else:
                validated_params[key] = str(value)
    
    # Database connection
    try:
        connection = pymysql.connect(
            host=os.environ['DB_HOST'],
            user=os.environ['DB_USER'],
            password=os.environ['DB_PASSWORD'],
            database=os.environ['DB_NAME'],
            charset='utf8mb4',
            cursorclass=pymysql.cursors.DictCursor,
            connect_timeout=5,
            read_timeout=5,
            write_timeout=5
        )
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': 'Database connection failed'})
        }
    
    try:
        with connection.cursor() as cursor:
            # Build dynamic query
            sql = "SELECT * FROM products WHERE 1=1"
            params = []
            
            if 'name' in validated_params:
                sql += " AND name LIKE %s"
                params.append(f"%{validated_params['name']}%")
                
            if 'category' in validated_params:
                sql += " AND category = %s"
                params.append(validated_params['category'])
                
            if 'price_min' in validated_params:
                sql += " AND price >= %s"
                params.append(validated_params['price_min'])
                
            if 'price_max' in validated_params:
                sql += " AND price <= %s"
                params.append(validated_params['price_max'])
                
            sql += " ORDER BY name"
            
            if 'limit' in validated_params:
                sql += " LIMIT %s"
                params.append(validated_params['limit'])
            
            cursor.execute(sql, params)
            results = cursor.fetchall()
            
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'products': results,
                'count': len(results)
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': 'Search failed'})
        }
    finally:
        connection.close()